def prove_pm5_32(sys: System) -> Proof:
    """Distribution of implication over biconditional.  Theorem *5.32 of
    [WhiteheadRussell] p. 125.  (Contributed by NM, 1-Aug-1994.)
    """
    lb = ProofBuilder(sys, "pm5.32")
    s1 = lb.ref("s1", "( ( ψ ↔ χ ) ↔ ( ¬ ψ ↔ ¬ χ ) )", ref="notbi", note="notbi")
    s2 = lb.ref("s2", "( ( φ → ( ψ ↔ χ ) ) ↔ ( φ → ( ¬ ψ ↔ ¬ χ ) ) )", s1, ref="imbi2i", note="imbi2i")
    s3 = lb.ref("s3", "( ( φ → ( ¬ ψ ↔ ¬ χ ) ) ↔ ( ( φ → ¬ ψ ) ↔ ( φ → ¬ χ ) ) )", ref="pm5.74", note="pm5.74")
    s4 = lb.ref("s4", "( ( ( φ → ¬ ψ ) ↔ ( φ → ¬ χ ) ) ↔ ( ¬ ( φ → ¬ ψ ) ↔ ¬ ( φ → ¬ χ ) ) )", ref="notbi", note="notbi")
    s5 = lb.ref("s5", "( ( φ → ( ψ ↔ χ ) ) ↔ ( ¬ ( φ → ¬ ψ ) ↔ ¬ ( φ → ¬ χ ) ) )", s2, s3, s4, ref="3bitri", note="3bitri")
    s6 = lb.ref("s6", "( ( φ ∧ ψ ) ↔ ¬ ( φ → ¬ ψ ) )", ref="df-an", note="df-an")
    s7 = lb.ref("s7", "( ( φ ∧ χ ) ↔ ¬ ( φ → ¬ χ ) )", ref="df-an", note="df-an")
    s8 = lb.ref("s8", "( ( ( φ ∧ ψ ) ↔ ( φ ∧ χ ) ) ↔ ( ¬ ( φ → ¬ ψ ) ↔ ¬ ( φ → ¬ χ ) ) )", s6, s7, ref="bibi12i", note="bibi12i")
    res = lb.ref("res", "( ( φ → ( ψ ↔ χ ) ) ↔ ( ( φ ∧ ψ ) ↔ ( φ ∧ χ ) ) )", s5, s8, ref="bitr4i", note="bitr4i")
    return lb.build(res)

