def prove_bitr(sys: System) -> Proof:
    """Theorem *4.22 of [WhiteheadRussell] p. 117. ~ bitri in closed form.
    (Contributed by NM, 3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "bitr")
    s1 = lb.ref("s1", "( ( φ ↔ ψ ) → ( ( φ ↔ χ ) ↔ ( ψ ↔ χ ) ) )", ref="bibi1", note="bibi1")
    res = lb.ref("res", "( ( ( φ ↔ ψ ) ∧ ( ψ ↔ χ ) ) → ( φ ↔ χ ) )", s1, ref="biimpar", note="biimpar")
    return lb.build(res)

def prove_biantr(sys: System) -> Proof:
    """A transitive law of equivalence.  Compare Theorem *4.22 of
    [WhiteheadRussell] p. 117.  (Contributed by NM, 18-Aug-1993.)
    """
    lb = ProofBuilder(sys, "biantr")
    s1 = lb.ref("s1", "( ( χ ↔ ψ ) → ( χ ↔ ψ ) )", ref="id", note="id")
    s2 = lb.ref("s2", "( ( χ ↔ ψ ) → ( ( φ ↔ χ ) ↔ ( φ ↔ ψ ) ) )", s1, ref="bibi2d", note="bibi2d")
    res = lb.ref("res", "( ( ( φ ↔ ψ ) ∧ ( χ ↔ ψ ) ) → ( φ ↔ χ ) )", s2, ref="biimparc", note="biimparc")
    return lb.build(res)

def prove_pm4_14(sys: System) -> Proof:
    """Theorem *4.14 of [WhiteheadRussell] p. 117.  Related to ~ con34b .
    (Contributed by NM, 3-Jan-2005.)  (Proof shortened by Wolf Lammen,
    23-Oct-2012.)
    """
    lb = ProofBuilder(sys, "pm4.14")
    s1 = lb.ref("s1", "( ( ψ → χ ) ↔ ( ¬ χ → ¬ ψ ) )", ref="con34b", note="con34b")
    s2 = lb.ref("s2", "( ( φ → ( ψ → χ ) ) ↔ ( φ → ( ¬ χ → ¬ ψ ) ) )", s1, ref="imbi2i", note="imbi2i")
    s3 = lb.ref("s3", "( ( ( φ ∧ ψ ) → χ ) ↔ ( φ → ( ψ → χ ) ) )", ref="impexp", note="impexp")
    s4 = lb.ref("s4", "( ( ( φ ∧ ¬ χ ) → ¬ ψ ) ↔ ( φ → ( ¬ χ → ¬ ψ ) ) )", ref="impexp", note="impexp")
    res = lb.ref("res", "( ( ( φ ∧ ψ ) → χ ) ↔ ( ( φ ∧ ¬ χ ) → ¬ ψ ) )", s2, s3, s4, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

