def prove_biadanid(sys: System) -> Proof:
    """Deduction associated with ~ biadani .  Add a conjunction to an
    equivalence.  (Contributed by Thierry Arnoux, 16-Jun-2024.)
    """
    lb = ProofBuilder(sys, "biadanid")
